import { DOCUMENT } from '@angular/common';
import {
  Component,
  computed,
  DestroyRef,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import {
  NonNullableFormBuilder,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';

import { FloatLabel } from 'primeng/floatlabel';
import { ButtonModule } from 'primeng/button';
import { PasswordModule } from 'primeng/password';
import { InputTextModule } from 'primeng/inputtext';
import { SelectChangeEvent, SelectModule } from 'primeng/select';
import { MessageModule } from 'primeng/message';

import { AuthService } from '../../../../core/services/auth.service';
import { AuthTokenManagerService } from '../../../../core/services/auth-token-manager.service';
import { environment } from '../../../../../environments/environment';
import { ApiUrlService } from '../../../../core/services/api-url.service';
import { UserSessionService } from '../../../../core/services/user-session.service';
import { take } from 'rxjs';
import { takeUntilDestroyed, toSignal } from '@angular/core/rxjs-interop';
import { isDefined } from '../../../../shared/utils';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { ThemeDataService } from '../../../../shared/services/theme-data.service';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { DEFAULT_SYSTEM_ID } from '../../../../core/models';
import { UserSessionNavigationService } from '../../../../core/services/user-session-navigation.service';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../../core/services/language.service';

@Component({
  selector: 'app-login',
  imports: [
    RouterModule,
    ReactiveFormsModule,
    FloatLabel,
    ButtonModule,
    PasswordModule,
    InputTextModule,
    SelectModule,
    MessageModule,
    TranslatePipe,
  ],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss',
})
export class LoginComponent implements OnInit {
  private readonly document = inject(DOCUMENT);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly authService = inject(AuthService);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly authDataService = inject(AuthDataService);
  private readonly themeDataService = inject(ThemeDataService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly fb = inject(NonNullableFormBuilder);
  private readonly userSessionService = inject(UserSessionService);
  private readonly userSessionNavigationService = inject(
    UserSessionNavigationService,
  );
  protected readonly destroyRef = inject(DestroyRef);
  private readonly translateService = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  readonly environment = environment;
  readonly apiOptions = environment.apiUrls.map((url) => ({
    label: url,
    value: url,
  }));
  readonly languages = [
    { label: 'English', value: 'en' },
    { label: 'Français', value: 'fr' },
    { label: 'Español', value: 'es' },
    { label: 'Português', value: 'pt' },
    { label: 'Nederlands', value: 'nl' },
    { label: 'Deutsch', value: 'de' },
    { label: 'Italiano', value: 'it' },
  ];
  readonly selectedLanguage = this.languageService.currentLanguage;
  private readonly domainTheme = toSignal(this.themeDataService.domainTheme$, {
    initialValue: null,
  });

  loginForm = this.fb.group({
    username: this.fb.control('', Validators.required),
    password: this.fb.control('', Validators.required),
    apiUrl: this.fb.control('', Validators.required),
  });

  currentYear: number = new Date().getFullYear();
  loading = false;
  isTokenLogin = signal(false);
  tokenLoginError = signal(false);
  readonly loginTitle = computed(() => {
    this.languageService.currentLanguage();
    const owner = this.domainTheme()?.domain?.owner;
    const ownerName = owner?.id === DEFAULT_SYSTEM_ID ? null : owner?.name;
    return isDefined(ownerName)
      ? this.translateService.instant('AUTH.LOGIN.TITLE_WITH_OWNER', {
          ownerName,
        })
      : this.translateService.instant('AUTH.LOGIN.TITLE');
  });

  ngOnInit(): void {
    this.clearAllSessionData();
    this.initializeApiUrl();

    // Subscribe to query param changes to handle token login
    this.route.queryParams
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((params) => {
        if (isDefined(params['token'])) {
          // Token present - start token login flow
          this.isTokenLogin.set(true);
          this.tokenLoginError.set(false);
          this.handleTokenLogin(params['token']);
        } else if (!this.tokenLoginError()) {
          this.resetToNormalLogin();
        }
      });
  }

  private clearAllSessionData(): void {
    this.authDataService.clearAllUserData();
    this.userSessionService.clearAllSessions();
    this.authTokenManagerService.clearTokens();
    this.themeDataService.clearTheme();
    this.clientDataService.reset();
  }

  private resetToNormalLogin(): void {
    // Reset all token login state to show normal form
    this.isTokenLogin.set(false);
    this.loading = false;
  }

  private handleTokenLogin(token: string): void {
    this.loading = true;
    this.authService
      .loginWithToken(token)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (result) => {
          void (async () => {
            try {
              // Store tokens and set user sessions
              this.authTokenManagerService.storeTokens(result);
              this.userSessionService.setUserSessions(result.users);

              // Navigate based on number of accounts
              if (result.users.length > 1) {
                await this.router.navigate(['/auth', 'context-selection'], {
                  queryParams: { resetPassword: 'true' },
                });
              } else if (result.users.length === 1) {
                this.userSessionService.setCurrentUserSession(
                  result.users[0].id,
                );
                await this.router.navigate(['/auth', 'reset-password-welcome']);
              }
            } catch {
              // Navigation failed (e.g., resolver error) - clear authentication state
              this.clearAllSessionData();
              this.loading = false;
              this.isTokenLogin.set(false);
              this.tokenLoginError.set(true);
              // Remove token from URL to trigger queryParams subscription
              void this.router.navigate(['/auth/login'], {
                replaceUrl: true,
              });
            } finally {
              this.loading = false;
            }
          })();
        },
        error: () => {
          // Token login failed - show the form
          this.loading = false;
          this.isTokenLogin.set(false);
          this.tokenLoginError.set(true);
          // Remove token from URL
          void this.router.navigate([], {
            relativeTo: this.route,
            queryParams: {},
            replaceUrl: true,
          });
        },
      });
  }

  private initializeApiUrl(): void {
    // If API dropdown is not shown, use the first API URL without showing the dropdown
    if (!environment.showApiDropdown) {
      const firstApiUrl = environment.apiUrls[0];
      if (firstApiUrl) {
        this.apiUrlService.setApiUrl(firstApiUrl);
        this.loginForm.controls.apiUrl.setValue(firstApiUrl);
      }
      return;
    }

    // Only when API dropdown is enabled, initialize it
    const currentUrl = this.apiUrlService.getCurrentApiUrl();
    const firstOptionUrl = this.apiOptions[0]?.value;

    if (!firstOptionUrl) {
      this.loginForm.controls.apiUrl.disable();
      return;
    }

    const isValidOption = this.apiOptions.some(
      (option) => option.value === currentUrl,
    );

    let initialApiUrl: string;
    if (isValidOption) {
      initialApiUrl = currentUrl;
    } else {
      initialApiUrl = firstOptionUrl;
      this.apiUrlService.setApiUrl(initialApiUrl);
    }

    this.loginForm.controls.apiUrl.setValue(initialApiUrl);
  }

  onSubmit() {
    if (this.loginForm.valid) {
      this.clearAllSessionData();
      this.loading = true;
      const { username, password } = this.loginForm.getRawValue();

      this.authService
        .login(username, password)
        .pipe(takeUntilDestroyed(this.destroyRef))
        .subscribe({
          next: (result) => {
            void (async () => {
              try {
                this.authTokenManagerService.storeTokens(result);
                this.userSessionService.setUserSessions(result.users);

                const returnUrl =
                  this.route.snapshot.queryParams['returnUrl'] ?? null;

                await this.userSessionNavigationService.navigateBasedOnSessions(
                  result.users,
                  returnUrl,
                );

                this.loading = false;
              } catch {
                // Navigation failed - clear authentication state
                this.clearAllSessionData();
                this.loading = false;
                this.loginForm.controls.password.reset();
              }
            })();
          },
          error: () => {
            this.loading = false;
            this.loginForm.controls.password.reset();
          },
        });
    }
  }

  onLanguageChange(lang: string): void {
    this.languageService.onManualLanguageChange(lang);
  }

  onApiUrlChange(event: SelectChangeEvent) {
    this.apiUrlService.setApiUrl(event.value);
    this.refetchDomainTheme();
  }

  private refetchDomainTheme(): void {
    const hostname = this.document.location.hostname;
    this.themeDataService
      .getDomainTheme(hostname)
      .pipe(take(1))
      .subscribe({
        next: (theme) => this.themeDataService.setTheme(theme),
        error: (err) => console.error('Failed to load domain theme:', err),
      });
  }
}
