import { Component, DestroyRef, inject, OnInit, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { NavigationEnd, Router, RouterModule } from '@angular/router';
import { ButtonModule } from 'primeng/button';
import { filter } from 'rxjs';
import { NetworkAnimationComponent } from '../../../../shared/components/network-animation/network-animation.component';
import { ThemeComponent } from '../../../../shared/components/theme/theme.component';
import { ThemeDataService } from '../../../../shared/services/theme-data.service';

@Component({
  selector: 'app-container',
  imports: [
    RouterModule,
    ButtonModule,
    NetworkAnimationComponent,
    ThemeComponent,
  ],
  templateUrl: './container.component.html',
  styleUrl: './container.component.scss',
})
export class ContainerComponent implements OnInit {
  isRouteActive = signal(false);
  private readonly router = inject(Router);
  private readonly destroyRef = inject(DestroyRef);
  private readonly themeDataService = inject(ThemeDataService);
  logoPath = signal('');
  logoError = signal(false);

  onLogoError(): void {
    this.logoError.set(true);
  }

  ngOnInit(): void {
    // Only navigate if we're at the base /auth route
    // Preserve query parameters when navigating
    if (this.router.url === '/auth' || this.router.url === '/auth/') {
      const urlTree = this.router.parseUrl(this.router.url);
      const queryParams = urlTree.queryParams;
      this.router.navigate(['/auth/login'], { queryParams }).catch(() => {});
    }

    this.router.events
      .pipe(
        filter((event) => event instanceof NavigationEnd),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe(() => {
        this.isRouteActive.set(this.router.url !== '/auth');
      });

    this.themeDataService.domainTheme$
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((theme) => {
        this.logoError.set(false);
        this.logoPath.set(theme?.['logoPath'] ?? '');
      });
  }
}
