import { HttpClient } from '@angular/common/http';
import {
  Component,
  OnInit,
  inject,
  ChangeDetectorRef,
  signal,
} from '@angular/core';
import { FormGroup, Validators } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';

import { AccountsService } from '../../../../api';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { DynamicFormComponent } from '../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  FormFieldConfig,
  FormAction,
  createTextField,
  createDropdownField,
  createPasswordField,
  GroupValues,
} from '../../../../shared/models';
import { isNullOrUndefined } from '../../../../shared/utils';
import { UserSessionService } from '../../../../core/services/user-session.service';
import { ButtonModule } from 'primeng/button';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';

@Component({
  selector: 'app-reset-password-welcome',
  imports: [DynamicFormComponent, ButtonModule, RouterModule, TranslatePipe],
  templateUrl: './reset-password-welcome.component.html',
  styleUrl: './reset-password-welcome.component.scss',
})
export class ResetPasswordWelcomeComponent implements OnInit {
  private readonly http = inject(HttpClient);
  private readonly authDataService = inject(AuthDataService);
  private readonly accountsService = inject(AccountsService);
  private readonly userSessionService = inject(UserSessionService);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly router = inject(Router);
  private readonly translate = inject(TranslateService);

  formFields: FormFieldConfig[] = [];
  protected readonly isSubmitting = signal<boolean>(false);
  timezones: { label: string; value: string }[] = [];

  currentYear: number = new Date().getFullYear();

  actions: FormAction[] = [];

  ngOnInit(): void {
    this.initializeActions();
    this.initializeFormFields();
    this.loadTimezones();
  }

  private initializeActions(): void {
    this.actions = [
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
        visible: false,
      },
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.UPDATE'),
        action: (formData: FormGroup) => {
          this.onSubmit(formData);
        },
        severity: 'primary',
        disabled: (form?: FormGroup) =>
          isNullOrUndefined(form) || form.pristine,
        styleClass: 'w-[120px] h-[50px] !text-white rounded border-none',
      },
    ];
  }

  private initializeFormFields(): void {
    const profile = this.userSessionService.currentUserSession();
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.NAME'),
        profile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'AUTH.RESET_PASSWORD.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextField(
        'emailAddress',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.EMAIL'),
        profile?.['emailAddress'],
        {
          name: 'email',
          validations: [
            {
              name: 'email',
              validator: Validators.email,
              message: this.translate.instant(
                'SHARED.COMMON.VALIDATION.INVALID_EMAIL',
              ),
            },
          ],
        },
      ),
      createTextField(
        'mobile',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.MOBILE'),
        profile?.['mobile']?.trim(),
        {
          name: 'mobile',
          validations: [
            {
              name: 'pattern',
              validator: Validators.pattern('^[0-9]*$'),
              message: this.translate.instant(
                'AUTH.RESET_PASSWORD.VALIDATION.MOBILE_PATTERN',
              ),
            },
          ],
        },
      ),
      createDropdownField(
        'timeZoneId',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.TIMEZONE'),
        this.timezones, // Will be empty initially, updated after timezones load
        profile?.timeZoneId,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: this.translate.instant('SHARED.COMMON.SELECTION.TITLE', {
            type: this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.TIMEZONE'),
          }),
          name: 'timeZone',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createPasswordField(
        'password',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.PASSWORD'),
        {
          name: 'password',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'AUTH.RESET_PASSWORD.FIELDS.PASSWORD',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];
  }

  private updateFormFields(): void {
    const profile = this.authDataService.getUserProfile();
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.NAME'),
        profile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'AUTH.RESET_PASSWORD.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextField(
        'emailAddress',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.EMAIL'),
        profile?.['emailAddress'],
        {
          name: 'email',
          validations: [
            {
              name: 'email',
              validator: Validators.email,
              message: this.translate.instant(
                'SHARED.COMMON.VALIDATION.INVALID_EMAIL',
              ),
            },
          ],
        },
      ),
      createTextField(
        'mobile',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.MOBILE'),
        profile?.['mobile']?.trim(),
        {
          name: 'mobile',
          validations: [
            {
              name: 'pattern',
              validator: Validators.pattern('^[0-9]*$'),
              message: this.translate.instant(
                'AUTH.RESET_PASSWORD.VALIDATION.MOBILE_PATTERN',
              ),
            },
          ],
        },
      ),
      createDropdownField(
        'timeZoneId',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.TIMEZONE'),
        this.timezones,
        profile?.timeZoneId,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: this.translate.instant(
            'AUTH.RESET_PASSWORD.FIELDS.TIMEZONE_PLACEHOLDER',
          ),
          name: 'timeZone',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createPasswordField(
        'password',
        this.translate.instant('AUTH.RESET_PASSWORD.FIELDS.PASSWORD'),
        {
          name: 'password',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'AUTH.RESET_PASSWORD.FIELDS.PASSWORD',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];
  }

  private loadTimezones(): void {
    this.http
      .get<{ id: string; name: string }[]>('/assets/docs/timezones.json')
      .subscribe((data) => {
        this.timezones = data
          .map((tz) => ({ label: tz.id, value: tz.id }))
          .sort((a, b) => a.label.localeCompare(b.label));
        // Update form fields with loaded timezones
        this.updateFormFields();
        this.cdr.detectChanges();
      });
  }

  private getDirtyValues(group: FormGroup): GroupValues {
    return Object.fromEntries(
      Object.entries(group.controls)
        .filter(([_, control]) => control.dirty)
        .map(([key, control]) => [key, control.value]),
    );
  }

  onSubmit(formGroup: FormGroup): void {
    const profile = this.userSessionService.currentUserSession();
    if (isNullOrUndefined(profile)) return;

    this.isSubmitting.set(true);

    const dirtyValues = this.getDirtyValues(formGroup);

    if (Object.keys(dirtyValues).length > 0) {
      this.accountsService.updateUser(profile.id, dirtyValues).subscribe({
        next: (result) => {
          void this.authDataService.setUserProfile(result);
        },
        complete: () => {
          this.isSubmitting.set(false);
          this.cdr.detectChanges();
          // Navigate to the app after successful password reset
          void this.router.navigate(['/position']);
        },
      });
    } else {
      this.isSubmitting.set(false);
    }
  }
}
